module top_module(clk, rst, en, count);input clk, rst, en;
  output reg [1:0] count;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst) begin
      count <= 2'b0;
    end else if (en) begin
      count <= count + 2'b1;
    end
  end

endmodule
